const body = $input.first().json.body || {};
const projectId = 'track_' + Date.now();
const provider = body.provider || 'openai';
const model = provider === 'openai' ? 'gpt-4o-mini' : provider === 'anthropic' ? 'claude-3-5-sonnet-20241022' : provider === 'mistral' ? 'mistral-medium-latest' : 'deepseek-chat';
const metadata = {
  project_id: projectId,
  provider: provider,
  title: body.title || 'Untitled Track',
  genre: body.genre || 'electronic',
  mood: body.mood || 'epic',
  concept: {},
  assets: {},
  timestamps: [],
  uploads: { youtube: false, tiktok: false, instagram: false },
  analytics: {},
  created_at: new Date().toISOString()
};
const prompt = `You are a music marketing expert. Create a detailed concept for a ${metadata.genre} track titled "${metadata.title}" with a ${metadata.mood} mood.\n\nReturn ONLY a JSON object with these keys:\nsuno_prompt: a detailed prompt for Suno AI to generate the track\nleonardo_prompt: a prompt for Leonardo AI to generate cover art\nyoutube_title: title for YouTube\nyoutube_description: description for YouTube (include hashtags)\ntiktok_caption: caption for TikTok (include hashtags)\ninstagram_caption: caption for Instagram (include hashtags)\nhook: the main viral hook of the song (1 sentence)\n`;
const bodyJson = JSON.stringify({ provider, prompt, model, temperature: 0.8, max_tokens: 1024 });
return [{ json: { projectId, provider, prompt, model, metadata, bodyJson } }];

const aiResponse = items[0].json;
const createMetadata = $('Create Metadata').all()[0].json;
const aiText = aiResponse.text;
const projectId = createMetadata.projectId;
const provider = createMetadata.provider;
const metadata = createMetadata.metadata;
let concept = {};
try {
  concept = JSON.parse(aiText);
} catch (e) {
  concept = { raw: aiText };
}
metadata.concept = concept;
metadata.concept.provider = provider;
const ffmpegBody = JSON.stringify({ project_id: projectId, task: 'render_long', schema: 'music_ai', cover_path: 'assets/cover.png', audio_path: 'assets/audio.mp3', output_path: 'outputs/video_long.mp4' });
return [{ json: { projectId, metadata, metadataJson: JSON.stringify(metadata), ffmpegBody } }];
